1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
4	const BLOCK_OF_THREE_DISCOUNT = 15;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number };
16	type QuoteStep = { op: "quote"; items: Array<Item> };
17	type Scenario = {
18	  customer: { yearsWithMHPCO: number };
19	  steps: Array<QuoteStep>;
20	};
21	
22	const roundUpInMHPCOFavor = (amount: number): number =>
23	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
24	
25	const CURSE_SURCHARGE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	
29	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
30	
31	const curseSurchargeFor = (item: Item): number =>
32	  item.cursed ? basePremiumOf(item) * CURSE_SURCHARGE : 0;
33	
34	const highEnchantmentSurchargeFor = (item: Item): number =>
35	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
36	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE
37	    : 0;
38	
39	const sumOfBasePrices = (items: Array<Item>): number =>
40	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
41	
42	const sumOfItemSurcharges = (items: Array<Item>): number =>
43	  items.reduce(
44	    (sum, item) => sum + curseSurchargeFor(item) + highEnchantmentSurchargeFor(item),
45	    0,
46	  );
47	
48	const COMPONENT_TYPES = ["rune", "moonstone"];
49	const BLOCK_SIZE = 3;
50	
51	const countOfType = (items: Array<Item>, type: string): number =>
52	  items.filter((item) => item.type === type).length;
53	
54	const formsABlock = (items: Array<Item>, type: string): boolean =>
55	  countOfType(items, type) === BLOCK_SIZE;
56	
57	const blockDiscountFor = (items: Array<Item>): number =>
58	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
59	  BLOCK_OF_THREE_DISCOUNT;
60	
61	const basePremiumFor = (items: Array<Item>): number =>
62	  sumOfBasePrices(items) - blockDiscountFor(items);
63	
64	const withFirstInsuranceSurcharge = (amount: number): number =>
65	  amount * (1 + FIRST_INSURANCE_SURCHARGE);
66	
67	const withProcessingFee = (amount: number): number => amount + PROCESSING_FEE;
68	
69	const quoteStep = (step: QuoteStep): { premium: number } => {
70	  const basePremium = basePremiumFor(step.items);
71	  const itemSurchargeTotal = sumOfItemSurcharges(step.items);
72	  const premiumBeforeRounding = withProcessingFee(
73	    withFirstInsuranceSurcharge(basePremium) + itemSurchargeTotal,
74	  );
75	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
76	};
77	
78	export const processScenario = (scenario: unknown): unknown => {
79	  const { steps } = scenario as Scenario;
80	  return { results: steps.map(quoteStep) };
81	};
